-- Seed data for audit logs (repeatable migration)
-- This file will be executed on every migration run after the initial setup

-- Clear existing audit logs
DELETE FROM audit_logs;

-- Insert sample audit log entries
-- These use hardcoded UUIDs for demonstration purposes
-- In production, these would be generated by actual system actions

-- Sample member-related audit logs
INSERT INTO audit_logs (member_id, entity_id, entity_type, action, description, created_at)
SELECT 
  m.id,
  m.id,
  'member',
  'CREATE',
  'Created member account for ' || m.firstname || ' ' || m.lastname,
  NOW() - INTERVAL '30 days'
FROM members m
WHERE m.email = 'john.doe@example.com'
LIMIT 1;

INSERT INTO audit_logs (member_id, entity_id, entity_type, action, description, created_at)
SELECT 
  m.id,
  m.id,
  'member',
  'UPDATE',
  'Updated profile information for ' || m.firstname || ' ' || m.lastname,
  NOW() - INTERVAL '25 days'
FROM members m
WHERE m.email = 'john.doe@example.com'
LIMIT 1;

-- Sample trainer-related audit logs
INSERT INTO audit_logs (member_id, entity_id, entity_type, action, description, created_at)
SELECT 
  m.id,
  t.member_id,
  'trainer',
  'CREATE',
  'Promoted ' || m.firstname || ' ' || m.lastname || ' to trainer',
  NOW() - INTERVAL '15 days'
FROM members m
INNER JOIN trainers t ON m.id = t.member_id
LIMIT 1;

-- Sample plan-related audit logs
INSERT INTO audit_logs (member_id, entity_id, entity_type, action, description, created_at)
SELECT 
  (SELECT m.id FROM members m INNER JOIN trainers t ON m.id = t.member_id LIMIT 1),
  p.id,
  'plan',
  'CREATE',
  'Created subscription plan: ' || p.name,
  NOW() - INTERVAL '40 days'
FROM plans p
LIMIT 1;

INSERT INTO audit_logs (member_id, entity_id, entity_type, action, description, created_at)
SELECT 
