-- Generate additional sample audit logs for testing pagination
INSERT INTO audit_logs (member_id, entity_id, entity_type, action, description, created_at)
SELECT 
  (SELECT id FROM members LIMIT 1),
  gen_random_uuid(),
  CASE (gs.i % 5)
    WHEN 0 THEN 'member'
    WHEN 1 THEN 'subscription'
    WHEN 2 THEN 'plan'
    WHEN 3 THEN 'payment'
    ELSE 'equipment'
  END,
  CASE (gs.i % 3)
    WHEN 0 THEN 'CREATE'
    WHEN 1 THEN 'UPDATE'
    ELSE 'DELETE'
  END,
  'Sample audit log entry ' || gs.i,
  NOW() - gs.i * INTERVAL '1 hour'
FROM generate_series(1, 50) AS gs(i);

